export default {
  name: "about-header",
  data() {
    return {
      allSelect: true,
	  use10cards: true
    };
  },
  methods: {
    setAllSelect() {
      this.allSelect = !this.allSelect;
      this.$store.commit("SET_ALLSELECT", this.allSelect);
    },
		
	setUse10cards() {
		this.use10cards = !this.use10cards;
		this.$store.commit("SET_USE10CARDS", this.use10cards);
	}
  }
};
